$path = "D:\이력서\AVEVA - Marine Principal Technical Support & Consultant – PLM SME, Busan\Proposal\Future_Industrial_PLM_Meeting_Deck_EN_V5.pptx"
$ppt = New-Object -ComObject PowerPoint.Application
try {
    $pres = $ppt.Presentations.Open($path, $true, $false, $false)
    Write-Output ("SLIDE SIZE: W=" + $pres.PageSetup.SlideWidth + " H=" + $pres.PageSetup.SlideHeight)
    foreach ($idx in 13,14,15) {
        $slide = $pres.Slides.Item($idx)
        Write-Output "`n===== SLIDE $idx : $($slide.Shapes.Count) shapes ====="
        foreach ($sh in $slide.Shapes) {
            $txt = ""
            if ($sh.HasTextFrame -eq -1 -and $sh.TextFrame.HasText -eq -1) {
                $txt = ($sh.TextFrame.TextRange.Text -replace "[\r\n]"," ").Trim()
                if ($txt.Length -gt 32) { $txt = $txt.Substring(0,32) + "..." }
            }
            $line = "{0,-26} L={1,6:N0} T={2,6:N0} W={3,6:N0} H={4,6:N0}  [{5}]" -f $sh.Name, $sh.Left, $sh.Top, $sh.Width, $sh.Height, $txt
            Write-Output $line
        }
    }
    $pres.Close()
} finally {
    $ppt.Quit()
    [System.Runtime.InteropServices.Marshal]::ReleaseComObject($ppt) | Out-Null
}

